import{_ as p}from"./plugin-vue_export-helper-c27b6911.js";import{r as e,o,c,a as n,b as a,d as t,e as l}from"./app-be253e4c.js";const u={},i=n("h1",{id:"数据类型",tabindex:"-1"},[n("a",{class:"header-anchor",href:"#数据类型","aria-hidden":"true"},"#"),a(" 数据类型")],-1),k=n("strong",null,"在模型中定义的每一列都必须具有数据类型。",-1),r=n("code",null,"Sequelize",-1),d={href:"https://github.com/sequelize/sequelize/blob/master/lib/data-types.js",target:"_blank",rel:"noopener noreferrer"},m=l(`<p>要访问内置数据类型，必须导入 <code>DataTypes</code>：</p><div class="language-javascript" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// 引入模块，解构出 DataTypes</span>
<span class="token keyword">const</span> <span class="token punctuation">{</span>DataTypes<span class="token punctuation">}</span> <span class="token operator">=</span> <span class="token function">require</span><span class="token punctuation">(</span><span class="token string">&quot;sequelize&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre></div><h2 id="基础类型" tabindex="-1"><a class="header-anchor" href="#基础类型" aria-hidden="true">#</a> 基础类型</h2><h3 id="字符串" tabindex="-1"><a class="header-anchor" href="#字符串" aria-hidden="true">#</a> 字符串</h3><div class="language-javascript" data-ext="js"><pre class="language-javascript"><code>DataTypes<span class="token punctuation">.</span><span class="token constant">STRING</span>             <span class="token comment">// VARCHAR(255)</span>
DataTypes<span class="token punctuation">.</span><span class="token constant">STRING</span><span class="token punctuation">(</span><span class="token number">1234</span><span class="token punctuation">)</span>       <span class="token comment">// VARCHAR(1234)</span>
DataTypes<span class="token punctuation">.</span><span class="token constant">STRING</span><span class="token punctuation">.</span><span class="token constant">BINARY</span>      <span class="token comment">// VARCHAR BINARY</span>
DataTypes<span class="token punctuation">.</span><span class="token constant">TEXT</span>               <span class="token comment">// TEXT</span>
DataTypes<span class="token punctuation">.</span><span class="token constant">TEXT</span><span class="token punctuation">(</span><span class="token string">&#39;tiny&#39;</span><span class="token punctuation">)</span>       <span class="token comment">// TINYTEXT</span>

<span class="token comment">// 仅支持 PostgreSQL 和 SQLite.</span>
DataTypes<span class="token punctuation">.</span><span class="token constant">CITEXT</span>             <span class="token comment">// CITEXT          </span>
</code></pre></div><h3 id="布尔" tabindex="-1"><a class="header-anchor" href="#布尔" aria-hidden="true">#</a> 布尔</h3><div class="language-javascript" data-ext="js"><pre class="language-javascript"><code>DataTypes<span class="token punctuation">.</span><span class="token constant">BOOLEAN</span>            <span class="token comment">// TINYINT(1)</span>
</code></pre></div><h3 id="数字" tabindex="-1"><a class="header-anchor" href="#数字" aria-hidden="true">#</a> 数字</h3><div class="language-javascript" data-ext="js"><pre class="language-javascript"><code>DataTypes<span class="token punctuation">.</span><span class="token constant">INTEGER</span>            <span class="token comment">// INTEGER</span>
DataTypes<span class="token punctuation">.</span><span class="token constant">BIGINT</span>             <span class="token comment">// BIGINT</span>
DataTypes<span class="token punctuation">.</span><span class="token constant">BIGINT</span><span class="token punctuation">(</span><span class="token number">11</span><span class="token punctuation">)</span>         <span class="token comment">// BIGINT(11)</span>

DataTypes<span class="token punctuation">.</span><span class="token constant">FLOAT</span>              <span class="token comment">// FLOAT</span>
DataTypes<span class="token punctuation">.</span><span class="token constant">FLOAT</span><span class="token punctuation">(</span><span class="token number">11</span><span class="token punctuation">)</span>          <span class="token comment">// FLOAT(11)</span>
DataTypes<span class="token punctuation">.</span><span class="token constant">FLOAT</span><span class="token punctuation">(</span><span class="token number">11</span><span class="token punctuation">,</span> <span class="token number">10</span><span class="token punctuation">)</span>      <span class="token comment">// FLOAT(11,10)</span>

DataTypes<span class="token punctuation">.</span><span class="token constant">REAL</span>               <span class="token comment">// REAL            仅支持 PostgreSQL.</span>
DataTypes<span class="token punctuation">.</span><span class="token constant">REAL</span><span class="token punctuation">(</span><span class="token number">11</span><span class="token punctuation">)</span>           <span class="token comment">// REAL(11)        仅支持 PostgreSQL.</span>
DataTypes<span class="token punctuation">.</span><span class="token constant">REAL</span><span class="token punctuation">(</span><span class="token number">11</span><span class="token punctuation">,</span> <span class="token number">12</span><span class="token punctuation">)</span>       <span class="token comment">// REAL(11,12)     仅支持 PostgreSQL.</span>

DataTypes<span class="token punctuation">.</span><span class="token constant">DOUBLE</span>             <span class="token comment">// DOUBLE</span>
DataTypes<span class="token punctuation">.</span><span class="token constant">DOUBLE</span><span class="token punctuation">(</span><span class="token number">11</span><span class="token punctuation">)</span>         <span class="token comment">// DOUBLE(11)</span>
DataTypes<span class="token punctuation">.</span><span class="token constant">DOUBLE</span><span class="token punctuation">(</span><span class="token number">11</span><span class="token punctuation">,</span> <span class="token number">10</span><span class="token punctuation">)</span>     <span class="token comment">// DOUBLE(11,10)</span>

DataTypes<span class="token punctuation">.</span><span class="token constant">DECIMAL</span>            <span class="token comment">// DECIMAL</span>
DataTypes<span class="token punctuation">.</span><span class="token constant">DECIMAL</span><span class="token punctuation">(</span><span class="token number">10</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">)</span>     <span class="token comment">// DECIMAL(10,2)</span>
</code></pre></div><h4 id="无符号和零填充整数" tabindex="-1"><a class="header-anchor" href="#无符号和零填充整数" aria-hidden="true">#</a> 无符号和零填充整数</h4><blockquote><p>仅支持MySQL、MariaDB数据库</p></blockquote><p>在 <code>MySQL</code> 和 <code>MariaDB</code> 中，可以将数据类型<code>INTEGER</code>、 <code>BIGINT</code> 、 <code>FLOAT</code> 和 <code>DOUBLE</code> 设置为无符号或零填充(或两者)，如下所示：</p><div class="language-javascript" data-ext="js"><pre class="language-javascript"><code>DataTypes<span class="token punctuation">.</span><span class="token constant">INTEGER</span><span class="token punctuation">.</span><span class="token constant">UNSIGNED</span>
DataTypes<span class="token punctuation">.</span><span class="token constant">INTEGER</span><span class="token punctuation">.</span><span class="token constant">ZEROFILL</span>
DataTypes<span class="token punctuation">.</span><span class="token constant">INTEGER</span><span class="token punctuation">.</span><span class="token constant">UNSIGNED</span><span class="token punctuation">.</span><span class="token constant">ZEROFILL</span>
</code></pre></div><ul><li>可以指定大小，即：<code>INTEGER(10)</code>而不是简单的<code>INTEGER</code></li><li>同样适用于 <code>BIGINT</code>、 <code>FLOAT</code> 和 <code>DOUBLE</code></li></ul><h3 id="日期" tabindex="-1"><a class="header-anchor" href="#日期" aria-hidden="true">#</a> 日期</h3><div class="language-javascript" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// DATETIME 适用于 mysql / sqlite， 带时区的TIMESTAMP 适用于 postgres</span>
DataTypes<span class="token punctuation">.</span><span class="token constant">DATE</span>

<span class="token comment">// DATETIME(6) 适用于 mysql 5.6.4+. 支持6位精度的小数秒</span>
DataTypes<span class="token punctuation">.</span><span class="token constant">DATE</span><span class="token punctuation">(</span><span class="token number">6</span><span class="token punctuation">)</span>

<span class="token comment">// 不带时间的 DATE</span>
DataTypes<span class="token punctuation">.</span><span class="token constant">DATEONLY</span>   
</code></pre></div><h3 id="uuid" tabindex="-1"><a class="header-anchor" href="#uuid" aria-hidden="true">#</a> UUID</h3><p>可以通过 <code>DataTypes.UUID</code>使用<code>UUID</code>，生成随机字符串</p><ul><li>对于 <code>PostgreSQL</code> 和 <code>SQLite</code>，它会是 <code>UUID</code> 数据类型</li><li>对于 <code>MySQL</code> ，它则变成<code>CHAR(36)</code></li></ul><p>使用 <code>Sequelize.UUIDV1</code> 或 <code>Sequelize.UUIDV4</code>作为默认值，可以自动为这些字段生成 <code>UUID</code>值，例如：</p><div class="language-javascript" data-ext="js"><pre class="language-javascript"><code><span class="token punctuation">{</span>
  <span class="token literal-property property">type</span><span class="token operator">:</span> DataTypes<span class="token punctuation">.</span><span class="token constant">UUID</span>
  <span class="token comment">// 或者默认值使用 Sequelize.UUIDV1</span>
  <span class="token literal-property property">defaultValue</span><span class="token operator">:</span>  Sequelize<span class="token punctuation">.</span><span class="token constant">UUIDV4</span>
<span class="token punctuation">}</span>
</code></pre></div><h2 id="其他类型" tabindex="-1"><a class="header-anchor" href="#其他类型" aria-hidden="true">#</a> 其他类型</h2><p>不同的数据库，存在一些特有的数据类型，这里按照不同数据库进行整理。</p><h3 id="范围类型" tabindex="-1"><a class="header-anchor" href="#范围类型" aria-hidden="true">#</a> 范围类型</h3><blockquote><p>只针对PostgreSQL数据库，支持范围类型</p></blockquote><div class="language-javascript" data-ext="js"><pre class="language-javascript"><code>DataTypes<span class="token punctuation">.</span><span class="token constant">RANGE</span><span class="token punctuation">(</span>DataTypes<span class="token punctuation">.</span><span class="token constant">INTEGER</span><span class="token punctuation">)</span>    <span class="token comment">// int4range</span>
DataTypes<span class="token punctuation">.</span><span class="token constant">RANGE</span><span class="token punctuation">(</span>DataTypes<span class="token punctuation">.</span><span class="token constant">BIGINT</span><span class="token punctuation">)</span>     <span class="token comment">// int8range</span>
DataTypes<span class="token punctuation">.</span><span class="token constant">RANGE</span><span class="token punctuation">(</span>DataTypes<span class="token punctuation">.</span><span class="token constant">DATE</span><span class="token punctuation">)</span>       <span class="token comment">// tstzrange</span>
DataTypes<span class="token punctuation">.</span><span class="token constant">RANGE</span><span class="token punctuation">(</span>DataTypes<span class="token punctuation">.</span><span class="token constant">DATEONLY</span><span class="token punctuation">)</span>   <span class="token comment">// daterange</span>
DataTypes<span class="token punctuation">.</span><span class="token constant">RANGE</span><span class="token punctuation">(</span>DataTypes<span class="token punctuation">.</span><span class="token constant">DECIMAL</span><span class="token punctuation">)</span>    <span class="token comment">// numrange</span>
</code></pre></div><h3 id="数组类型" tabindex="-1"><a class="header-anchor" href="#数组类型" aria-hidden="true">#</a> 数组类型</h3><blockquote><p>只针对PostgreSQL数据库，支持数组类型</p></blockquote><div class="language-javascript" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// 定义数组类型</span>
DataTypes<span class="token punctuation">.</span><span class="token constant">ARRAY</span><span class="token punctuation">(</span><span class="token comment">/* DataTypes.SOMETHING */</span><span class="token punctuation">)</span>

<span class="token comment">// VARCHAR(255)[]</span>
DataTypes<span class="token punctuation">.</span><span class="token constant">ARRAY</span><span class="token punctuation">(</span>DataTypes<span class="token punctuation">.</span><span class="token constant">STRING</span><span class="token punctuation">)</span>

<span class="token comment">// VARCHAR(255)[][]</span>
DataTypes<span class="token punctuation">.</span><span class="token constant">ARRAY</span><span class="token punctuation">(</span>DataTypes<span class="token punctuation">.</span><span class="token constant">ARRAY</span><span class="token punctuation">(</span>DataTypes<span class="token punctuation">.</span><span class="token constant">STRING</span><span class="token punctuation">)</span><span class="token punctuation">)</span>
</code></pre></div><h3 id="二进制类型" tabindex="-1"><a class="header-anchor" href="#二进制类型" aria-hidden="true">#</a> 二进制类型</h3><blockquote><p>只针对PostgreSQL数据库，支持BLOB二进制类型</p></blockquote><div class="language-javascript" data-ext="js"><pre class="language-javascript"><code>DataTypes<span class="token punctuation">.</span><span class="token constant">BLOB</span>                <span class="token comment">// BLOB (bytea for PostgreSQL)</span>
DataTypes<span class="token punctuation">.</span><span class="token constant">BLOB</span><span class="token punctuation">(</span><span class="token string">&#39;tiny&#39;</span><span class="token punctuation">)</span>        <span class="token comment">// TINYBLOB (bytea for PostgreSQL)</span>
DataTypes<span class="token punctuation">.</span><span class="token constant">BLOB</span><span class="token punctuation">(</span><span class="token string">&#39;medium&#39;</span><span class="token punctuation">)</span>      <span class="token comment">// MEDIUMBLOB (bytea for PostgreSQL)</span>
DataTypes<span class="token punctuation">.</span><span class="token constant">BLOB</span><span class="token punctuation">(</span><span class="token string">&#39;long&#39;</span><span class="token punctuation">)</span>        <span class="token comment">// LONGBLOB (bytea for PostgreSQL)</span>
</code></pre></div><p><code>BLOB</code>二进制允许以<code>字符串</code>和<code>缓冲区</code>的形式插入数据。 但是，当使用 <code>Sequelize</code> 从数据库检索 <code>blob</code> 时，它将始终作为缓冲区检索</p><h3 id="枚举类型" tabindex="-1"><a class="header-anchor" href="#枚举类型" aria-hidden="true">#</a> 枚举类型</h3><p><code>ENUM</code> 是一种仅接受少数值的数据类型，指定为列表，提供可选值供选择。例如：</p><div class="language-javascript" data-ext="js"><pre class="language-javascript"><code>DataTypes<span class="token punctuation">.</span><span class="token constant">ENUM</span><span class="token punctuation">(</span><span class="token string">&#39;foo&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;bar&#39;</span><span class="token punctuation">)</span> <span class="token comment">// An ENUM with allowed values &#39;foo&#39; and &#39;bar&#39;</span>
</code></pre></div><p>可以使用<code>values</code>字段来指明<code>ENUM</code>可选值</p><div class="language-javascript" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// 使用values字段来维护枚举</span>
sequelize<span class="token punctuation">.</span><span class="token function">define</span><span class="token punctuation">(</span><span class="token string">&#39;user&#39;</span><span class="token punctuation">,</span> <span class="token punctuation">{</span>
  <span class="token literal-property property">states</span><span class="token operator">:</span> <span class="token punctuation">{</span>
    <span class="token literal-property property">type</span><span class="token operator">:</span> DataTypes<span class="token punctuation">.</span><span class="token constant">ENUM</span><span class="token punctuation">,</span>
    <span class="token literal-property property">values</span><span class="token operator">:</span> <span class="token punctuation">[</span><span class="token string">&#39;create&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;update&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;delete&#39;</span><span class="token punctuation">]</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre></div><h3 id="json类型" tabindex="-1"><a class="header-anchor" href="#json类型" aria-hidden="true">#</a> JSON类型</h3><p><code>SQLite</code>、<code>MySQL</code>、<code>MariaDB</code>、<code>Oracle</code> 和 <code>PostgreSQL</code>数据库都一定程度上支持<code>JSON</code>数据类型，例如：</p><p><strong><code>PostgreSQL</code> 中的 <code>JSON</code> 数据类型将值存储为纯文本，而不是二进制表示形式。</strong></p><ul><li>如果只想存储和检索 <code>JSON</code> 表示形式，那么使用 <code>JSON</code> 将占用更少的磁盘空间和从其输入表示形式构建的时间。</li><li>如果想对 <code>JSON</code> 值执行任何操作，可以是使用<code>JSONB</code>类型。</li></ul>`,42),T=n("code",null,"PostgreSQL",-1),h=n("code",null,"JSONB",-1),D={href:"https://geek-docs.com/postgresql/postgresql-questions/762_postgresql_sequelize_query_on_jsonb_array.html",target:"_blank",rel:"noopener noreferrer"};function g(y,E){const s=e("ExternalLinkIcon");return o(),c("div",null,[i,n("p",null,[k,a(),r,a(" 提供很多"),n("a",d,[a("内置数据类型"),t(s)]),a("。")]),m,n("p",null,[T,a(" 还支持 "),h,a(" 数据类型，具体使用可以参考："),n("a",D,[a("Sequelize中JSONB的查询"),t(s)])])])}const N=p(u,[["render",g],["__file","db-datatype.html.vue"]]);export{N as default};
